	for key, value := range order {
		if err := vm.Set(key, value); err != nil {
			return 0.0, fmt.Errorf("failed to inject variable %s: %w", key, err)
		}
	}

	// DoS Protection: Set a timeout to interrupt long-running or infinite scripts
	// This ensures the script execution does not hang the process.
	timeout := 2 * time.Second
	timer := time.AfterFunc(timeout, func() {
		vm.Interrupt("script execution timeout")
	})
	defer timer.Stop()

	// Execute the script
	// In Goja, the result of the last evaluated expression is returned
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Export the result to a Go type
	exported := result.Export()

	// Handle cases where the script returns null, undefined, or nothing
	if exported == nil {
		return 0.0, fmt.Errorf("script must return a number, but got null or undefined")
	}

	// Convert the exported value to float64.
	// Goja exports JS numbers as int64 (for integers) or float64 (for decimals).
	switch v := exported.(type) {
	case float64:
		return v, nil
	case int64:
		return float64(v), nil
	case int:
		return float64(v), nil
	case int32:
		return float64(v), nil
	case float32:
		return float64(v), nil
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", v)
	}
}

