import (
	"context"
	"errors"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM.
// It includes security measures like execution timeouts to prevent DoS attacks.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// --- Security: Execution Timeout ---
	// Create a context with a timeout (e.g., 1 second) to prevent infinite loops.
	ctx, cancel := context.WithTimeout(context.Background(), 1*time.Second)
	defer cancel()

	// Use a watchdog goroutine to interrupt the VM if the context expires.
	done := make(chan struct{})
	defer close(done)

	go func() {
		select {
		case <-ctx.Done():
			// This will cause vm.RunString to return an error immediately.
			vm.Interrupt(errors.New("script execution timed out"))
		case <-done:
			// Script finished execution normally.
		}
	}()

	// --- Inject Global Variables ---
	// Inject the entire order map as a global object named "order".
	// This fixes the "ReferenceError: order is not defined" error.
	if err := vm.Set("order", order); err != nil {
		return 0.0, fmt.Errorf("failed to set global variable 'order': %w", err)
	}

	// Also inject individual order fields into the VM's global scope for convenience.
	for key, value := range order {
		if err := vm.Set(key, value); err != nil {
			return 0.0, fmt.Errorf("failed to set global variable %q: %w", key, err)
		}
	}

	// --- Script Execution ---
	result, err := vm.RunString(script)
	if err != nil {
		// Check if the error was caused by the timeout interruption.
		if errors.Is(ctx.Err(), context.DeadlineExceeded) {
			return 0.0, fmt.Errorf("security violation: script execution exceeded time limit")
		}
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// --- Result Conversion and Validation ---
	if result == nil || goja.IsUndefined(result) || goja.IsNull(result) {
		return 0.0, errors.New("script must return a value, but returned undefined or null")
	}

	// JavaScript numbers are valid even if they are NaN or Infinity, 
	// but these are invalid for financial calculations.
	if goja.IsNaN(result) || goja.IsInfinity(result) {
		return 0.0, errors.New("script returned an invalid numeric value (NaN or Infinity)")
	}

	// Goja exports JS numbers as int64 (for whole numbers) or float64.
	// We handle various numeric types to ensure the discount is captured correctly.
	var discount float64
	export := result.Export()
	switch v := export.(type) {
	case float64:
		discount = v
	case int64:
		discount = float64(v)
	case int:
		discount = float64(v)
	case float32:
		discount = float64(v)
	default:
		return 0.0, fmt.Errorf("script must return a number, got %T", export)
	}

	return discount, nil
}

