import (
	"errors"
	"fmt"
	"math"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM.
// It implements security best practices such as execution timeouts, panic recovery,
// and strict type validation to prevent Denial of Service and unexpected behavior.
func CalculateDiscount(script string, order map[string]interface{}) (discount float64, err error) {
	if script == "" {
		return 0, errors.New("discount script is empty")
	}

	// Create a new Goja VM instance. 
	// Creating a fresh VM per execution ensures isolation and thread safety.
	vm := goja.New()

	// 1. Security: Panic Recovery
	// Recovers from any unexpected panics within the Goja engine during execution.
	defer func() {
		if r := recover(); r != nil {
			err = fmt.Errorf("panic during script execution: %v", r)
		}
	}()

	// 2. Security: Timeout (DoS protection)
	// Prevents scripts with infinite loops or heavy computation from hanging the process.
	// 1-2 seconds is typically more than enough for simple business logic.
	timeout := 2 * time.Second
	timer := time.AfterFunc(timeout, func() {
		vm.Interrupt("script execution timeout")
	})
	defer timer.Stop()

	// 3. Inject variables
	// Inject the order map itself to support scripts accessing order properties (e.g., order.total).
	if err := vm.Set("order", order); err != nil {
		return 0, fmt.Errorf("failed to inject order object: %w", err)
	}

	// Inject order fields as global variables in the VM for convenience (e.g., total).
	for key, value := range order {
		if err := vm.Set(key, value); err != nil {
			return 0, fmt.Errorf("failed to inject variable %s: %w", key, err)
		}
	}

	// 4. Execute the script
	// The result of the script is the value of the last expression evaluated.
	result, err := vm.RunString(script)
	if err != nil {
		return 0, fmt.Errorf("script execution error: %w", err)
	}

	// 5. Handle and Validate Result
	if result == nil || goja.IsUndefined(result) || goja.IsNull(result) {
		return 0, errors.New("script did not return a value")
	}

	// Convert result to float64 safely.
	// Goja's Export() returns Go types (e.g., int64 for JS integers, float64 for decimals).
	// We handle multiple numeric types that might be returned or injected.
	exported := result.Export()
	switch v := exported.(type) {
	case float64:
		discount = v
	case int64:
		discount = float64(v)
	case int:
		discount = float64(v)
	case float32:
		discount = float64(v)
	case int32:
		discount = float64(v)
	default:
		return 0, fmt.Errorf("script must return a number, got %T", exported)
	}

	// 6. Security/Robustness: Check for invalid numbers
	// NaN or Infinity are valid JS numbers but represent errors in business logic.
	if math.IsNaN(discount) || math.IsInf(discount, 0) {
		return 0, errors.New("script returned an invalid number (NaN or Infinity)")
	}

	return discount, nil
}

func main() {
	// Example usage
	order := map[string]interface{}{
		"total":     250.0,
		"userLevel": "VIP",
	}

	// Example script: 20% discount for VIPs, 5% for others
	script := `
		if (userLevel === "VIP") {
			total * 0.2;
		} else {
			total * 0.05;
		}
	`

	discount, err := CalculateDiscount(script, order)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		return
	}

	fmt.Printf("Order Total: %.2f\n", order["total"])
	fmt.Printf("Discount: %.2f\n", discount)
	fmt.Printf("Final Price: %.2f\n", order["total"].(float64)-discount)
}

